\begin {aligned}
 H { \left ( P,Q \right )}  &= C { \left ( P,Q \right )} \\ 
 H { \left ( M,N \right )}  &= D { \left ( M,N \right )} \\ 
 H { \left ( P,N \right )}  &=  \mathcal {O}_{ F \dashv  G } { \left ( P,N \right )}  = C { \left ( P,GN \right )} \\ 
 H { \left ( N,P \right )}  &=  \varnothing 
\end {aligned}

\begin {aligned}
 K { \left ( M,N \right )}  &= D_S { \left ( M,N \right )}  = D { \left ( SM,N \right )}  = C { \left ( GM,GN \right )} 
  \\  
 K { \left ( P,Q \right )}  &= C_T { \left ( P,Q \right )}  = C { \left ( P,TQ \right )}  = D { \left ( FP,FQ \right )} 
  \\ 
 K { \left ( N,P \right )}  &=  \mathcal {O}_{ G' \dashv  F' } { \left ( N,P \right )}  = D_S { \left ( N,F'P \right )}  = D { \left ( SN,FP \right )}  = C { \left ( GN,TP \right )} 
  \\  
 K { \left ( P,N \right )}  &=  \varnothing 
\end {aligned}
